/**
 * Order validation — pure functions for validating order data.
 *
 * No side effects, no database calls. These validators can be
 * reused across services and tested in isolation.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';

/**
 * Valid order status transitions.
 * Each key maps to the statuses it can transition to.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate that an order has at least one item.
 * Throws if the items array is empty.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate a status transition, throwing if invalid.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * User validation — pure functions for validating user data.
 *
 * No side effects, no database calls. These validators can be
 * reused across services and tested in isolation.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Check whether an email address has a valid format.
 */
export function isValidEmail(email: string): boolean {
  return EMAIL_REGEX.test(email);
}

/**
 * Validate an email address format, throwing if invalid.
 */
export function validateEmail(email: string): void {
  if (!isValidEmail(email)) {
    throw new Error(`Invalid email format: ${email}`);
  }
}

/**
 * Notification preference validation — pure functions for checking
 * whether a notification should be sent based on user preferences.
 *
 * No side effects, no database calls. Operates on already-fetched
 * preference objects.
 */

import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';

/**
 * Determine whether a notification should be sent based on stored preferences.
 *
 * Returns true if the notification should proceed, false if suppressed.
 * If preferences is null/undefined, returns true (send everything by default).
 */
export function shouldSendNotification(
  prefs: UserPreferences | undefined,
  channel: NotificationChannel,
  type: NotificationType,
): boolean {
  if (!prefs) {
    return true;
  }

  if (channel === 'email') {
    if (!prefs.email.enabled) {
      return false;
    }
    if (!prefs.email.subscribedCategories.includes(type)) {
      return false;
    }
    return true;
  }

  // For channels without preference support yet, allow by default
  return true;
}

