import { describe, it, expect } from 'vitest';
import {
  validateOrderItems,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';

describe('Order Validators', () => {
  describe('validateOrderItems', () => {
    it('should pass for non-empty items array', () => {
      expect(() =>
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw for empty items array', () => {
      expect(() => validateOrderItems([])).toThrow(
        'Order must have at least one item',
      );
    });

    it('should pass for multiple items', () => {
      expect(() =>
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 2, unitPrice: 20 },
        ]),
      ).not.toThrow();
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('delivered', 'shipped')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'shipped')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'delivered')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
      expect(() => validateStatusTransition('confirmed', 'shipped')).not.toThrow();
      expect(() => validateStatusTransition('shipped', 'delivered')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
      expect(() => validateStatusTransition('delivered', 'shipped')).toThrow(
        'Invalid status transition: delivered -> shipped',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import { isValidEmail, validateEmail } from '../../src/validators/user.validator.js';

describe('User Validators', () => {
  describe('isValidEmail', () => {
    it('should accept valid email addresses', () => {
      expect(isValidEmail('alice@example.com')).toBe(true);
      expect(isValidEmail('bob@test.org')).toBe(true);
      expect(isValidEmail('user.name@domain.co')).toBe(true);
    });

    it('should reject emails without @', () => {
      expect(isValidEmail('aliceexample.com')).toBe(false);
    });

    it('should reject emails without domain', () => {
      expect(isValidEmail('alice@')).toBe(false);
    });

    it('should reject emails without local part', () => {
      expect(isValidEmail('@example.com')).toBe(false);
    });

    it('should reject emails with spaces', () => {
      expect(isValidEmail('alice @example.com')).toBe(false);
    });

    it('should reject empty string', () => {
      expect(isValidEmail('')).toBe(false);
    });
  });

  describe('validateEmail', () => {
    it('should not throw for valid email', () => {
      expect(() => validateEmail('alice@example.com')).not.toThrow();
    });

    it('should throw for invalid email', () => {
      expect(() => validateEmail('not-an-email')).toThrow('Invalid email format');
    });
  });
});

import { describe, it, expect } from 'vitest';
import { shouldSendNotification } from '../../src/validators/notification.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

function makePrefs(overrides?: Partial<UserPreferences['email']>): UserPreferences {
  return {
    id: 'pref-1',
    userId: 'user-1',
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: ['order-confirmation', 'order-status-update', 'welcome', 'account-updated'],
      ...overrides,
    },
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

describe('Notification Validators', () => {
  describe('shouldSendNotification', () => {
    it('should return true when preferences are undefined', () => {
      expect(shouldSendNotification(undefined, 'email', 'order-confirmation')).toBe(true);
    });

    it('should return true when email is enabled and subscribed', () => {
      const prefs = makePrefs();
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      const prefs = makePrefs({ enabled: false });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(false);
    });

    it('should return false when not subscribed to category', () => {
      const prefs = makePrefs({ subscribedCategories: ['welcome'] });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(false);
    });

    it('should return true when subscribed to specific category', () => {
      const prefs = makePrefs({ subscribedCategories: ['order-confirmation'] });
      expect(shouldSendNotification(prefs, 'email', 'order-confirmation')).toBe(true);
    });

    it('should return true for unsupported channels (default allow)', () => {
      const prefs = makePrefs();
      expect(shouldSendNotification(prefs, 'sms', 'order-confirmation')).toBe(true);
      expect(shouldSendNotification(prefs, 'webhook', 'welcome')).toBe(true);
    });
  });
});

